import { cn } from "@/lib/utils";
import { BookOpen, Play, CheckCircle2 } from "lucide-react";
import { Button } from "@/components/ui/button";
import { DomainId, DOMAIN_COLORS } from "@/lib/domain-colors";

export interface Lesson {
  title: string;
  description: string;
  domain: DomainId;
  duration: string;
  completed: boolean;
}

interface DailyLessonsProps {
  lessons: Lesson[];
  completedCount?: number;
  onViewAll?: () => void;
}

export function DailyLessons({ lessons, completedCount, onViewAll }: DailyLessonsProps) {
  const completed = completedCount ?? lessons.filter(l => l.completed).length;

  return (
    <div className="glass rounded-xl p-5 opacity-0 animate-fade-in" style={{ animationDelay: "500ms" }}>
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center gap-2">
          <BookOpen className="w-5 h-5 text-primary" />
          <h3 className="font-display font-semibold text-lg">Today's Lessons</h3>
        </div>
        <span className="text-sm text-muted-foreground">{completed}/{lessons.length} completed</span>
      </div>

      <div className="space-y-3">
        {lessons.map((lesson, index) => {
          const colors = DOMAIN_COLORS[lesson.domain];

          return (
            <div
              key={index}
              className={cn(
                "flex items-center gap-3 p-3 rounded-lg border transition-all cursor-pointer group",
                lesson.completed
                  ? "bg-muted/30 border-border/50 opacity-60"
                  : "bg-muted/50 border-border hover:border-primary/30"
              )}
            >
              <div
                className={cn(
                  "w-10 h-10 rounded-lg flex items-center justify-center flex-shrink-0 border",
                  colors.bgSubtle,
                  colors.border
                )}
              >
                {lesson.completed ? (
                  <CheckCircle2 className="w-5 h-5 text-finance" />
                ) : (
                  <Play className={cn("w-4 h-4", colors.text)} />
                )}
              </div>
              <div className="flex-1 min-w-0">
                <p
                  className={cn(
                    "font-medium text-sm truncate",
                    lesson.completed ? "text-muted-foreground line-through" : "text-foreground"
                  )}
                >
                  {lesson.title}
                </p>
                <p className="text-xs text-muted-foreground truncate">
                  {lesson.description}
                </p>
              </div>
              <div className="text-right flex-shrink-0">
                <span className={cn("text-xs font-medium", colors.text)}>
                  {lesson.duration}
                </span>
              </div>
            </div>
          );
        })}
      </div>

      <Button
        variant="ghost"
        className="w-full mt-4 text-muted-foreground hover:text-foreground"
        onClick={onViewAll}
      >
        View All Lessons
      </Button>
    </div>
  );
}

// Default lessons for backward compatibility
export const DEFAULT_LESSONS: Lesson[] = [
  {
    title: "Understanding Time Complexity",
    description: "Learn how to analyze algorithm efficiency using Big O notation",
    domain: "tech",
    duration: "15 min",
    completed: false,
  },
  {
    title: "Emergency Fund Basics",
    description: "Why you need 3-6 months of expenses saved before investing",
    domain: "finance",
    duration: "10 min",
    completed: true,
  },
  {
    title: "Reading Candlestick Patterns",
    description: "Identify bullish and bearish reversal patterns",
    domain: "trading",
    duration: "12 min",
    completed: false,
  },
  {
    title: "Chord Transition Techniques",
    description: "Practice switching between G, C, and D smoothly",
    domain: "music",
    duration: "20 min",
    completed: false,
  },
];

import { useState } from "react";
import { motion, Variants } from "framer-motion";
import { format } from "date-fns";
import { DevotionBanner } from "@/components/dashboard/widgets/DevotionBanner";
import { InteractiveCalendar } from "@/components/dashboard/widgets/InteractiveCalendar";
import { CompletionChart } from "@/components/dashboard/widgets/CompletionChart";
import { WeeklyActivityChart } from "@/components/dashboard/widgets/WeeklyActivityChart";
import { NotesWidget } from "@/components/dashboard/widgets/NotesWidget";
import { DomainFocusRadar } from "@/components/dashboard/widgets/DomainFocusRadar";
import { useChecklistEntries, useChecklistAnalytics, useToggleChecklistEntry } from "@/hooks/useChecklistEntries";
import { startOfMonth, endOfMonth } from "date-fns";

interface ZenLayoutProps {
  timeOfDay: "morning" | "evening";
}

const inkBrush: Variants = {
  hidden: { opacity: 0, x: -20, filter: "blur(2px)" },
  show: {
    opacity: 1,
    x: 0,
    filter: "blur(0px)",
    transition: {
      duration: 0.7,
      ease: [0.22, 1, 0.36, 1],
    },
  },
};

const zenStagger: Variants = {
  hidden: { opacity: 0 },
  show: {
    opacity: 1,
    transition: {
      staggerChildren: 0.12,
      delayChildren: 0.08,
    },
  },
};

// Zen card with paper texture feel
const ZenCard = ({ children, className = "" }: { children: React.ReactNode; className?: string }) => (
  <div className={`relative bg-card/80 backdrop-blur-sm rounded-xl border border-border/40 overflow-hidden ${className}`}>
    <div className="absolute inset-0 bg-gradient-to-br from-muted/5 to-transparent" />
    <div
      className="absolute inset-0 opacity-[0.015]"
      style={{
        backgroundImage: `url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noiseFilter'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.85' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noiseFilter)'/%3E%3C/svg%3E")`,
      }}
    />
    <div className="relative">{children}</div>
  </div>
);

export function ZenLayout({ timeOfDay }: ZenLayoutProps) {
  const [selectedDate, setSelectedDate] = useState(new Date());

  // Fetch checklist entries from the database
  const startDate = startOfMonth(new Date());
  const endDate = endOfMonth(new Date());
  const { data: entries = [] } = useChecklistEntries(startDate, endDate);
  const { data: analyticsEntries = [] } = useChecklistAnalytics(1);
  const toggleEntry = useToggleChecklistEntry();

  // Convert entries to the completed tasks format
  const completedTasks = entries.reduce((acc, entry) => {
    if (entry.is_completed) {
      if (!acc[entry.entry_date]) {
        acc[entry.entry_date] = [];
      }
      acc[entry.entry_date].push(entry.task_id);
    }
    return acc;
  }, {} as Record<string, string[]>);

  // Track all tasks (both completed and pending) for proper task list display
  const allTasksData = entries.reduce((acc, entry) => {
    if (!acc[entry.entry_date]) {
      acc[entry.entry_date] = [];
    }
    acc[entry.entry_date].push(entry.task_id);
    return acc;
  }, {} as Record<string, string[]>);

  const handleToggleTask = (dateKey: string, taskId: string, metricsData?: Record<string, any>) => {
    const entry = entries.find(e => e.task_id === taskId && e.entry_date === dateKey);
    const isCurrentlyCompleted = entry?.is_completed || false;
    toggleEntry.mutate({
      taskId,
      entryDate: dateKey,
      isCompleted: !isCurrentlyCompleted,
      metricsData,
    });
  };

  return (
    <motion.div
      initial="hidden"
      animate="show"
      exit={{ opacity: 0 }}
      variants={zenStagger}
      className="relative flex-1 flex flex-col gap-3 sm:gap-4"
    >
      {/* Top Row: Devotion + Workspaces (left 50%) + Calendar (right 50%) */}
      <motion.div variants={zenStagger} className="grid grid-cols-12 gap-3 sm:gap-4">
        {/* Left Column: Devotion + Workspaces stacked */}
        <motion.div variants={inkBrush} className="col-span-12 lg:col-span-6 flex flex-col gap-3 sm:gap-4">
          {/* Devotion Banner - Prominent */}
          <ZenCard>
            <DevotionBanner
              characterName="David"
              dayNumber={7}
              todayScripture="1 Samuel 17"
              timeOfDay={timeOfDay}
            />
          </ZenCard>

          {/* Notes/Workspaces - Below Devotion */}
          <ZenCard>
            <NotesWidget />
          </ZenCard>
        </motion.div>

        {/* Calendar - 50% width on right */}
        <motion.div variants={inkBrush} className="col-span-12 lg:col-span-6">
          <ZenCard className="h-full">
            <div className="p-3 sm:p-4 h-full">
              <InteractiveCalendar
                selectedDate={selectedDate}
                onSelectDate={setSelectedDate}
                completedTasks={completedTasks}
                allTasks={allTasksData}
                onToggleTask={handleToggleTask}
                entries={analyticsEntries}
              />
            </div>
          </ZenCard>
        </motion.div>
      </motion.div>

      {/* Analytics Row: 2 equal widgets (Performance Summary + Streak Stats) */}
      <motion.div variants={zenStagger} className="grid grid-cols-12 gap-3 sm:gap-4">
        {/* Weekly Activity Chart */}
        <motion.div variants={inkBrush} className="col-span-12 md:col-span-6">
          <ZenCard className="h-full min-h-[200px]">
            <WeeklyActivityChart />
          </ZenCard>
        </motion.div>

        {/* Domain Focus Radar */}
        <motion.div variants={inkBrush} className="col-span-12 md:col-span-6">
          <ZenCard className="h-full min-h-[150px]">
            <DomainFocusRadar />
          </ZenCard>
        </motion.div>
      </motion.div>
    </motion.div>
  );
}

import { useState, useMemo } from "react";
import { ChevronLeft, ChevronRight, TrendingUp } from "lucide-react";
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  Tooltip,
  ResponsiveContainer,
  Cell,
  type TooltipProps,
} from "recharts";
import { cn } from "@/lib/utils";
import { DOMAIN_COLORS, DomainId } from "@/lib/domain-colors";
import { useChecklistAnalytics } from "@/hooks/useChecklistEntries";
import {
  format,
  startOfWeek,
  endOfWeek,
  eachDayOfInterval,
  getDay,
  isToday as isTodayFn,
} from "date-fns";
import { STANDARD_TASKS } from "@/lib/constants";

interface DayActivity {
  day: string;
  tasks: number;
  total: number;
  hours: number;
  points: number;
  completed: boolean;
  completionRate: number;
  isToday: boolean;
  domainBreakdown: Record<string, number>;
}

export function WeeklyActivityChart() {
  const [weekOffset, setWeekOffset] = useState(0);
  const { data: analyticsData = [], isLoading } = useChecklistAnalytics(1);

  // Calculate week data from analytics
  const weekData = useMemo(() => {
    const today = new Date();
    const weekStart = startOfWeek(today);
    const weekEnd = endOfWeek(today);
    const daysOfWeek = eachDayOfInterval({ start: weekStart, end: weekEnd });

    return daysOfWeek.map((date) => {
      const dateKey = format(date, "yyyy-MM-dd");
      const dayOfWeek = getDay(date);

      // Get tasks for this day
      const dayTasks = analyticsData.filter(
        (entry) => entry.entry_date === dateKey,
      );

      // Calculate expected tasks for this day
      const expectedTasks = STANDARD_TASKS.filter((task) => {
        if (task.frequency === "daily") return true;
        if (task.frequency === "weekly" && task.daysOfWeek) {
          return task.daysOfWeek.includes(dayOfWeek);
        }
        return false;
      }).length;

      // Calculate totals
      const completedCount = dayTasks.length;
      const totalHours = dayTasks.reduce((sum, task) => {
        return sum + (task.duration_seconds || 0) / 3600;
      }, 0);

      // Domain breakdown
      const domainBreakdown: Record<string, number> = {};
      dayTasks.forEach((task) => {
        const taskId = task.task_id;
        const domain = taskId.split("_")[0]; // Extract domain from task_id (e.g., "tech_dsa" -> "tech")
        domainBreakdown[domain] = (domainBreakdown[domain] || 0) + 1;
      });

      const completionRate =
        expectedTasks > 0
          ? Math.round((completedCount / expectedTasks) * 100)
          : 0;

      return {
        day: format(date, "EEE"),
        tasks: completedCount,
        total: expectedTasks,
        hours: Math.round(totalHours * 10) / 10,
        points: 0, // Points will be added later when the column exists
        completed: completedCount >= expectedTasks,
        completionRate,
        isToday: isTodayFn(date),
        domainBreakdown,
      };
    });
  }, [analyticsData, weekOffset]);

  // Get bar color based on completion rate
  const getBarColor = (rate: number, isToday: boolean) => {
    if (isToday) return "hsl(var(--foreground))";
    if (rate >= 71) return "hsl(var(--finance))";
    if (rate >= 41) return "hsl(var(--trading))";
    return "hsl(var(--destructive) / 0.5)";
  };

  // Custom tooltip
  const CustomTooltip = ({ active, payload }: TooltipProps<number, string>) => {
    if (!active || !payload || !payload[0]) return null;

    const data = payload[0].payload as DayActivity;

    return (
      <div className="bg-card/95 backdrop-blur-sm border border-border rounded-lg p-3 shadow-lg z-50">
        <p className="font-medium text-sm mb-2">{data.day}</p>
        <div className="space-y-1 text-xs">
          <div className="flex items-center gap-2">
            <span className="text-muted-foreground">Tasks:</span>
            <span className="font-medium">
              {data.tasks}/{data.total}
            </span>
          </div>
          <div className="flex items-center gap-2">
            <span className="text-muted-foreground">Hours:</span>
            <span className="font-medium">{data.hours}h</span>
          </div>
          <div className="flex items-center gap-2">
            <span className="text-muted-foreground">Points:</span>
            <span className="font-medium">+{data.points}</span>
          </div>

          {Object.keys(data.domainBreakdown).length > 0 && (
            <>
              <div className="h-px bg-border my-1.5" />
              <p className="text-muted-foreground text-[10px] mb-1">
                By Domain:
              </p>
              {Object.entries(data.domainBreakdown)
                .sort(([, a], [, b]) => b - a)
                .map(([domain, count]) => (
                  <div key={domain} className="flex items-center gap-2">
                    <span
                      className={cn(
                        "text-[10px] capitalize",
                        DOMAIN_COLORS[domain as DomainId]?.text ||
                          "text-muted-foreground",
                      )}
                    >
                      {domain}:
                    </span>
                    <span className="text-[10px] font-medium">{count}</span>
                  </div>
                ))}
            </>
          )}
        </div>
      </div>
    );
  };

  const isCurrentWeek = weekOffset === 0;
  const weekLabel = "This Week";

  if (isLoading) {
    return (
      <div className="p-3 sm:p-4 h-full flex items-center justify-center">
        <p className="text-sm text-muted-foreground">Loading...</p>
      </div>
    );
  }

  return (
    <div className="p-3 sm:p-4 h-full flex flex-col">
      {/* Header with navigation */}
      <div className="flex items-center justify-between mb-3">
        <div className="flex items-center gap-2">
          <TrendingUp className="w-4 h-4 text-muted-foreground" />
          <h3 className="text-sm font-medium">Weekly Activity</h3>
        </div>
        <div className="flex items-center gap-1">
          <button
            onClick={() => setWeekOffset((prev) => prev - 1)}
            className="p-1 hover:bg-muted rounded transition-colors"
            aria-label="Previous week"
          >
            <ChevronLeft className="w-3.5 h-3.5 text-muted-foreground" />
          </button>
          <span className="text-xs text-muted-foreground min-w-[80px] text-center">
            {weekLabel}
          </span>
          <button
            onClick={() => setWeekOffset((prev) => prev + 1)}
            disabled={isCurrentWeek}
            className={cn(
              "p-1 hover:bg-muted rounded transition-colors",
              isCurrentWeek && "opacity-30 cursor-not-allowed",
            )}
            aria-label="Next week"
          >
            <ChevronRight className="w-3.5 h-3.5 text-muted-foreground" />
          </button>
        </div>
      </div>

      {/* Chart */}
      <div className="flex-1 min-h-[140px]">
        <ResponsiveContainer width="100%" height={140}>
          <BarChart
            data={weekData}
            margin={{ top: 10, right: 0, left: 0, bottom: 0 }}
          >
            <XAxis
              dataKey="day"
              axisLine={false}
              tickLine={false}
              tick={{ fontSize: 11, fill: "hsl(var(--muted-foreground))" }}
            />
            <YAxis hide domain={[0, 100]} />
            <Tooltip content={<CustomTooltip />} cursor={false} />
            <Bar dataKey="completionRate" radius={[4, 4, 0, 0]} maxBarSize={40}>
              {weekData.map((entry, index) => (
                <Cell
                  key={`cell-${index}`}
                  fill={getBarColor(entry.completionRate, entry.isToday)}
                  className={entry.isToday ? "animate-pulse" : ""}
                />
              ))}
            </Bar>
          </BarChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
}

import { Check, Droplets, Dumbbell, BookOpen, Moon, Apple } from "lucide-react";
import { cn } from "@/lib/utils";

interface Habit {
  id: string;
  icon: React.ElementType;
  label: string;
  completed: boolean;
  notes?: string;
  timerSeconds?: number;
}

interface DailyHabitsProps {
  date: Date;
  habits: Habit[];
  onToggle: (id: string) => void;
  compact?: boolean;
}

export function DailyHabits({ date, habits, onToggle, compact = false }: DailyHabitsProps) {
  if (compact) {
    return (
      <div className="grid grid-cols-2 gap-1.5">
        {habits.map((habit) => (
          <button
            key={habit.id}
            onClick={() => onToggle(habit.id)}
            className={cn(
              "flex items-center gap-2 p-2 rounded-lg transition-all text-left",
              "hover:bg-muted/50",
              habit.completed && "opacity-60"
            )}
          >
            <div className={cn(
              "w-6 h-6 rounded-full flex items-center justify-center transition-colors flex-shrink-0",
              habit.completed 
                ? "bg-primary/10 text-primary" 
                : "bg-muted text-muted-foreground"
            )}>
              {habit.completed ? (
                <Check className="w-3 h-3" />
              ) : (
                <habit.icon className="w-3 h-3" />
              )}
            </div>
            <span className={cn(
              "text-xs truncate",
              habit.completed && "line-through text-muted-foreground"
            )}>
              {habit.label}
            </span>
          </button>
        ))}
      </div>
    );
  }

  return (
    <div className="space-y-2">
      <div className="space-y-2">
        {habits.map((habit) => (
          <button
            key={habit.id}
            onClick={() => onToggle(habit.id)}
            className={cn(
              "w-full flex items-center gap-4 p-3 rounded-lg transition-all",
              "hover:bg-muted/50",
              habit.completed && "opacity-60"
            )}
          >
            <div className={cn(
              "w-8 h-8 rounded-full flex items-center justify-center transition-colors",
              habit.completed 
                ? "bg-primary/10 text-primary" 
                : "bg-muted text-muted-foreground"
            )}>
              {habit.completed ? (
                <Check className="w-4 h-4" />
              ) : (
                <habit.icon className="w-4 h-4" />
              )}
            </div>
            <span className={cn(
              "text-sm",
              habit.completed && "line-through text-muted-foreground"
            )}>
              {habit.label}
            </span>
          </button>
        ))}
      </div>
    </div>
  );
}

